// Extract payment info from GHL webhook payload
const body = $input.first().json.body || $input.first().json;

// GHL sends different event types:
// - order.completed
// - subscription.created  
// - invoice.paid

const contactEmail = body.contact?.email || body.email || '';
const contactPhone = body.contact?.phone || body.phone || '';
const contactId = body.contact?.id || body.contactId || body.contact_id || '';

// Determine tier from product/price ID
const PRODUCT_TO_TIER = {
  '69b5b769081db66d1afbf145': 'monthly',
  '69b5b777711f98f382f110ff': 'lifetime',
  '69b5b7791fe1a8f21eb651b5': 'yearly'
};

const PRICE_TO_TIER = {
  '69b5d533d314dc23b8a6f918': 'monthly',
  '69b5d535a0334430aa1f2eac': 'lifetime',
  '69b5d5371fe1a88dbdba1590': 'yearly',
  '69b5b794c6731008d7ae723c': 'monthly',
  '69b5b7a8081db612f9fbfe60': 'lifetime',
  '69b5b7ab247cf6a48020f434': 'yearly'
};

// Try to find product/price ID in various payload locations
const productId = body.product?.id || body.productId || 
  (body.items && body.items[0]?.product?.id) || 
  (body.lineItems && body.lineItems[0]?.productId) || '';

const priceId = body.price?.id || body.priceId ||
  (body.items && body.items[0]?.price?.id) ||
  (body.lineItems && body.lineItems[0]?.priceId) || '';

let tier = PRODUCT_TO_TIER[productId] || PRICE_TO_TIER[priceId] || null;

// Fallback: check amount
if (!tier) {
  const amount = body.amount || body.totalAmount || 
    (body.items && body.items[0]?.amount) || 0;
  if (amount === 99700 || amount === 997) tier = 'lifetime';
  else if (amount === 39700 || amount === 397) tier = 'yearly';
  else if (amount === 6700 || amount === 67) tier = 'monthly';
}

return [{
  json: {
    contactEmail,
    contactPhone,
    contactId,
    productId,
    priceId,
    tier: tier || 'monthly',
    rawEvent: body.type || body.event || 'unknown'
  }
}];
